Here's a solid pattern for testing async code with MSTest, using `MockHttpMessageHandler` to control responses:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Stub handler to control HttpClient behavior
    private sealed class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK)
        {
            Content = new StringContent("ok")
        };

        public Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>>? SendFunc { get; set; }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            return SendFunc?.Invoke(request, cancellationToken)
                ?? Task.FromResult(Response);
        }
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler
        {
            Response = new(HttpStatusCode.OK) { Content = new StringContent("payload") }
        };
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com");

        Assert.AreEqual("payload", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        var handler = new MockHandler
        {
            Response = new(HttpStatusCode.InternalServerError)
        };
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => sut.FetchAsync("https://example.com"));
    }

    // --- Cancellation & timeout tests ---

    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        var handler = new MockHandler();
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancelled

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        var handler = new MockHandler
        {
            SendFunc = async (_, ct) =>
            {
                await Task.Delay(Timeout.Infinite, ct); // blocks until cancelled
                throw new InvalidOperationException("unreachable");
            }
        };
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // safety net — test fails if it hangs
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHandler
        {
            Response = new(HttpStatusCode.OK) { Content = new StringContent("fast") }
        };
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}
```

**Key patterns demonstrated:**

| Concern | Technique |
|---|---|
| **Isolate HttpClient** | Custom `HttpMessageHandler` — no real HTTP calls |
| **Pre-cancelled token** | `cts.Cancel()` before calling, assert `TaskCanceledException` |
| **Mid-flight cancellation** | Handler blocks with `Task.Delay(Infinite, ct)`, short CTS timeout triggers cancel |
| **Hang protection** | `[Timeout(5000)]` on the test method as a safety net |
| **Always use `async Task`** | Never `async void` — MSTest awaits the returned `Task` correctly |

> **Tip:** Avoid `Thread.Sleep` in async tests — use `Task.Delay` with a `CancellationToken` so the test remains responsive and cancellable.
